/**
 * AuraLogo — Centralized logo component with multiple variants.
 *
 * Variants:
 *   "header"     → Horizontal: orb + "AURA ALPHA" text (logo-auraalpha-header.png) — navbars, headers
 *   "stacked"    → Vertical: orb + "AURA ALPHA" below (logo-auraalpha.png) — login, register, about hero
 *   "mark"       → Orb + "AURA" stacked, original full glow (logo-main.png) — splash, loading, watermark
 *   "compact"    → Horizontal: orb + "AURA" text (logo-ui.png) — sidebar, compact headers
 *   "watermark"  → Full-width semi-transparent background treatment
 *   "icon"       → Just the orb mark (cropped from logo-main.png via CSS)
 *
 * Props:
 *   variant   — one of the above (default "header")
 *   height    — CSS height value (default varies by variant)
 *   style     — extra inline styles
 *   glow      — adds a subtle glow/shadow effect
 *   className — optional
 */

const VARIANT_MAP = {
  header:    { src: '/images/logo-auraalpha-header.webp', fallback: '/images/logo-auraalpha-header.png', defaultH: 52 },
  stacked:   { src: '/images/logo-auraalpha.webp',        fallback: '/images/logo-auraalpha.png',        defaultH: 120 },
  mark:      { src: '/images/logo-main.webp',             fallback: '/images/logo-main.png',             defaultH: 160 },
  compact:   { src: '/images/logo-ui.png',                fallback: '/images/logo-ui.png',               defaultH: 44 },
  icon:      { src: '/images/logo-main.webp',             fallback: '/images/logo-main.png',             defaultH: 48 },
  watermark: { src: '/images/logo-auraalpha-header.webp', fallback: '/images/logo-auraalpha-header.png', defaultH: 'auto' },
}

export default function AuraLogo({
  variant = 'header',
  height,
  glow = false,
  style: extraStyle = {},
  className,
  onClick,
}) {
  const cfg = VARIANT_MAP[variant] || VARIANT_MAP.header
  const h = height || cfg.defaultH

  /* ── Watermark variant: full-width, subtle, background-style ── */
  if (variant === 'watermark') {
    return (
      <img
        src={cfg.src}
        alt=""
        loading="lazy"
        className={className}
        style={{
          position: 'absolute',
          top: '50%', left: '50%',
          transform: 'translate(-50%, -50%)',
          width: '100vw', minWidth: 900, maxWidth: 1600,
          height: 'auto',
          opacity: 0.12,
          pointerEvents: 'none',
          filter: 'brightness(1.4) saturate(0.8)',
          mixBlendMode: 'screen',
          ...extraStyle,
        }}
      />
    )
  }

  /* ── Icon variant: circular crop showing just the orb ── */
  if (variant === 'icon') {
    const size = typeof h === 'number' ? h : 40
    return (
      <div
        className={className}
        onClick={onClick}
        style={{
          width: size, height: size,
          borderRadius: '50%',
          overflow: 'hidden',
          flexShrink: 0,
          position: 'relative',
          cursor: onClick ? 'pointer' : 'default',
          boxShadow: glow
            ? '0 0 20px rgba(0,255,249,0.25), 0 0 40px rgba(88,166,255,0.15)'
            : 'none',
          ...extraStyle,
        }}
      >
        <img
          src={cfg.src}
          alt="AuraAlpha"
          loading="lazy"
          style={{
            position: 'absolute',
            top: '-20%', left: '-10%',
            width: '120%', height: '120%',
            objectFit: 'cover',
            objectPosition: 'center 35%',
          }}
        />
      </div>
    )
  }

  /* ── Standard image variants ── */
  const glowShadow = glow
    ? variant === 'mark' || variant === 'stacked'
      ? '0 0 30px rgba(0,255,249,0.2), 0 0 60px rgba(88,166,255,0.1)'
      : '0 0 16px rgba(0,255,249,0.15), 0 0 32px rgba(88,166,255,0.08)'
    : 'none'

  return (
    <img
      src={cfg.src}
      alt="AuraAlpha"
      loading="lazy"
      className={className}
      onClick={onClick}
      style={{
        height: typeof h === 'number' ? h : undefined,
        width: 'auto',
        objectFit: 'contain',
        filter: glow ? 'drop-shadow(0 0 8px rgba(0,255,249,0.2))' : 'none',
        cursor: onClick ? 'pointer' : 'default',
        ...extraStyle,
      }}
    />
  )
}

/**
 * AuraWordmark — Text-only brand rendering (no image needed).
 * Uses JetBrains Mono to match the brand font.
 *
 * Props:
 *   size     — font size (default 16)
 *   variant  — "full" (AURA alpha) | "short" (AURA) | "tagline"
 *   style    — extra inline styles
 */
export function AuraWordmark({
  size = 16,
  variant = 'full',
  style: extraStyle = {},
}) {
  const mono = "'JetBrains Mono', monospace"
  const blue = '#60A5FA'
  const primary = '#E5E7DB'

  if (variant === 'tagline') {
    return (
      <div style={{ fontFamily: mono, ...extraStyle }}>
        <span style={{ fontWeight: 800, fontSize: size, color: primary, letterSpacing: '-0.02em' }}>
          AURA<span style={{ color: blue }}>alpha</span>
        </span>
        <span style={{ fontSize: size * 0.65, color: '#90A3AF', marginLeft: 8, fontWeight: 400 }}>
          Institutional-Grade Algorithmic Trading
        </span>
      </div>
    )
  }

  return (
    <span style={{
      fontFamily: mono, fontWeight: 800, fontSize: size, color: primary,
      letterSpacing: '-0.02em',
      ...extraStyle,
    }}>
      AURA<span style={{ color: blue }}>{variant === 'short' ? '' : 'alpha'}</span>
    </span>
  )
}
